const { BigQuery } = require('@google-cloud/bigquery');

exports.processLargeDataset = async (event, context) => {
  const bigquery = new BigQuery();

  const query = `
    SELECT
      column1,
      SUM(column2) AS total
    FROM
      dataset.table
    GROUP BY
      column1
  `;

  const options = {
    query: query,
    location: 'us-central1', // Set the query location
    timeout: 540000, // Set the query timeout to 540 seconds
    maxResults: 1000000, // Set the maximum number of rows to return
    memory: '8GB', // Set the maximum memory allocation to 8GB
  };

  try {
    const [job] = await bigquery.createQueryJob(options);

    // Wait for the job to complete
    await job.promise();

    // Log the results
    console.log('Data aggregation completed.');
  } catch (err) {
    console.error('Error processing large dataset:', err);
    throw err;
  }
};